import{_ as e,c as o,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"上級: 高度な機能とワークフロー | oh-my-opencode","description":"oh-my-opencode の高度な機能を習得します。AI エージェントチーム、並列タスク、Categories/Skills システム、ライフサイクルフックなどのコア機能を学び、効率的な AI ワークフロー編成を実現します。","frontmatter":{"title":"上級: 高度な機能とワークフロー | oh-my-opencode","sidebarTitle":"チームのように働く","subtitle":"上級: 高度な機能とワークフロー","description":"oh-my-opencode の高度な機能を習得します。AI エージェントチーム、並列タスク、Categories/Skills システム、ライフサイクルフックなどのコア機能を学び、効率的な AI ワークフロー編成を実現します。","order":60},"headers":[],"relativePath":"ja/code-yeongyu/oh-my-opencode/advanced/index.md","filePath":"ja/code-yeongyu/oh-my-opencode/advanced/index.md"}'),r={name:"ja/code-yeongyu/oh-my-opencode/advanced/index.md"};function t(l,a,n,h,d,p){return s(),o("div",null,[...a[0]||(a[0]=[i(`<h1 id="上級" tabindex="-1">上級 <a class="header-anchor" href="#上級" aria-label="Permalink to &quot;上級&quot;">​</a></h1><p>本章では、oh-my-opencode の高度な機能について詳しく解説します：プロフェッショナルな AI エージェントチーム、並列バックグラウンドタスク、Categories と Skills システム、ライフサイクルフックなど。これらの機能を習得することで、本物のチームを管理するように AI ワークフローを編成し、より効率的な開発体験を実現できます。</p><h2 id="本章の内容" tabindex="-1">本章の内容 <a class="header-anchor" href="#本章の内容" aria-label="Permalink to &quot;本章の内容&quot;">​</a></h2><div class="grid-cards"><h3 id="ai-エージェントチーム-10-人の専門家の紹介" tabindex="-1"><a href="./ai-agents-overview/">AI エージェントチーム：10 人の専門家の紹介</a> <a class="header-anchor" href="#ai-エージェントチーム-10-人の専門家の紹介" aria-label="Permalink to &quot;[AI エージェントチーム：10 人の専門家の紹介](./ai-agents-overview/)&quot;">​</a></h3><p>10 人の組み込みエージェントの機能、使用シナリオ、呼び出し方法を包括的に紹介します。タスクの種類に応じて適切なエージェントを選択し、効率的なチーム協力、並列タスク実行、深いコード分析を実現できるようになります。</p><h3 id="prometheus-計画-インタビュー式要件収集" tabindex="-1"><a href="./prometheus-planning/">Prometheus 計画：インタビュー式要件収集</a> <a class="header-anchor" href="#prometheus-計画-インタビュー式要件収集" aria-label="Permalink to &quot;[Prometheus 計画：インタビュー式要件収集](./prometheus-planning/)&quot;">​</a></h3><p>インタビューモードを通じて要件を明確にし、作業計画を生成します。Prometheus は要件が明確になるまで継続的に質問し、Oracle、Metis、Momus に自動的に相談して計画の品質を検証します。</p><h3 id="バックグラウンド並列タスク-チームのように働く" tabindex="-1"><a href="./background-tasks/">バックグラウンド並列タスク：チームのように働く</a> <a class="header-anchor" href="#バックグラウンド並列タスク-チームのように働く" aria-label="Permalink to &quot;[バックグラウンド並列タスク：チームのように働く](./background-tasks/)&quot;">​</a></h3><p>バックグラウンドエージェント管理システムの使用方法について詳しく解説します。並列制御、タスクポーリング、結果取得を学び、複数の AI エージェントが同時に異なるタスクを処理できるようにし、作業効率を大幅に向上させます。</p><h3 id="lsp-と-ast-grep-コードリファクタリングツール" tabindex="-1"><a href="./lsp-ast-tools/">LSP と AST-Grep：コードリファクタリングツール</a> <a class="header-anchor" href="#lsp-と-ast-grep-コードリファクタリングツール" aria-label="Permalink to &quot;[LSP と AST-Grep：コードリファクタリングツール](./lsp-ast-tools/)&quot;">​</a></h3><p>LSP ツールと AST-Grep ツールの使用方法を紹介します。シンボルナビゲーション、参照検索、構造化コード検索など、IDE レベルのコード分析と操作を実装する方法を示します。</p><h3 id="categories-と-skills-動的エージェント構成" tabindex="-1"><a href="./categories-skills/">Categories と Skills：動的エージェント構成</a> <a class="header-anchor" href="#categories-と-skills-動的エージェント構成" aria-label="Permalink to &quot;[Categories と Skills：動的エージェント構成](./categories-skills/)&quot;">​</a></h3><p>Categories と Skills システムを使用して専門化されたサブエージェントを作成する方法を学びます。柔軟なエージェント構成を実装し、タスク要件に応じてモデル、ツール、スキルを動的に割り当てます。</p><h3 id="組み込み-skills-ブラウザ自動化と-git-専門家" tabindex="-1"><a href="./builtin-skills/">組み込み Skills：ブラウザ自動化と Git 専門家</a> <a class="header-anchor" href="#組み込み-skills-ブラウザ自動化と-git-専門家" aria-label="Permalink to &quot;[組み込み Skills：ブラウザ自動化と Git 専門家](./builtin-skills/)&quot;">​</a></h3><p>3 つの組み込み Skills（playwright、frontend-ui-ux、git-master）の使用シナリオとベストプラクティスを詳しく紹介します。ブラウザ自動化、フロントエンド UI デザイン、Git 操作などの専門機能に迅速にアクセスできます。</p><h3 id="ライフサイクルフック-自動化コンテキストと品質管理" tabindex="-1"><a href="./lifecycle-hooks/">ライフサイクルフック：自動化コンテキストと品質管理</a> <a class="header-anchor" href="#ライフサイクルフック-自動化コンテキストと品質管理" aria-label="Permalink to &quot;[ライフサイクルフック：自動化コンテキストと品質管理](./lifecycle-hooks/)&quot;">​</a></h3><p>32 のライフサイクルフックの使用方法を紹介します。コンテキスト注入、エラー回復、品質管理を自動化する方法を理解し、完全な AI ワークフロー自動化システムを構築します。</p><h3 id="スラッシュコマンド-プリセットワークフロー" tabindex="-1"><a href="./slash-commands/">スラッシュコマンド：プリセットワークフロー</a> <a class="header-anchor" href="#スラッシュコマンド-プリセットワークフロー" aria-label="Permalink to &quot;[スラッシュコマンド：プリセットワークフロー](./slash-commands/)&quot;">​</a></h3><p>6 つの組み込みスラッシュコマンドの使用方法を紹介します。/ralph-loop（クイックフィックスループ）、/refactor（コードリファクタリング）、/start-work（プロジェクト実行開始）など、一般的なワークフローが含まれます。</p><h3 id="設定深いカスタマイズ-エージェントと権限管理" tabindex="-1"><a href="./advanced-configuration/">設定深いカスタマイズ：エージェントと権限管理</a> <a class="header-anchor" href="#設定深いカスタマイズ-エージェントと権限管理" aria-label="Permalink to &quot;[設定深いカスタマイズ：エージェントと権限管理](./advanced-configuration/)&quot;">​</a></h3><p>エージェント設定、権限設定、モデルオーバーライド、プロンプト修正を深くカスタマイズする方法を教えます。完全な設定能力を習得し、チーム基準に合致する AI ワークフローを作成します。</p></div><h2 id="学習パス" tabindex="-1">学習パス <a class="header-anchor" href="#学習パス" aria-label="Permalink to &quot;学習パス&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  ステップ 1               ステップ 2                 ステップ 3                      ステップ 4                  │</span></span>
<span class="line"><span>│  AI エージェントチーム  →   計画と並列タスク   →   動的エージェント構成   →   深いカスタマイズと自動化    │</span></span>
<span class="line"><span>│  (基本概念)                 (コア能力)                  (高度な使用法)                  (エキスパートレベル)         │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>推奨される順序</strong>：</p><ol><li><strong>まず AI エージェントチームから</strong>：10 人のエージェントの責任と使用シナリオを理解します。これはシステム全体を理解するための礎石です。</li><li><strong>次に計画と並列タスクを学ぶ</strong>：Prometheus 計画とバックグラウンドタスクシステムを習得します。これは効率的な協力のコアです。</li><li><strong>続いて動的エージェント構成を学ぶ</strong>：Categories と Skills を学び、柔軟なエージェント専門化を実現します。</li><li><strong>最後に深いカスタマイズを学ぶ</strong>：ライフサイクルフック、スラッシュコマンド、設定カスタマイズを習得し、完全なワークフローを作成します。</li></ol><p><strong>上級ルート</strong>：</p><ul><li>目標が<strong>迅速な開始</strong>の場合：「AI エージェントチーム」と「スラッシュコマンド」に集中</li><li>目標が<strong>チーム協力</strong>の場合：「Prometheus 計画」と「バックグラウンド並列タスク」を深く学習</li><li>目標が<strong>ワークフロー自動化</strong>の場合：「ライフサイクルフック」と「設定深いカスタマイズ」を学習</li></ul><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">開始前に確認してください</p><p>本章の内容は、以下の学習を完了していることを前提としています：</p><ul><li>✅ <a href="./../start/installation/">迅速なインストールと設定</a>：oh-my-opencode をインストールし、少なくとも 1 つの Provider を設定済み</li><li>✅ <a href="./../start/sisyphus-orchestrator/">Sisyphus の初見：メインオーケストレーター</a>：基本エージェント呼び出しと委任メカニズムを理解済み</li><li>✅ <a href="./../platforms/provider-setup/">Provider 設定：Claude、OpenAI、Gemini</a>：少なくとも 1 つの AI Provider を設定済み</li></ul></div><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>本章を完了した後、以下の学習を続けることを推奨します：</p><ul><li><strong><a href="./../faq/troubleshooting/">設定診断とトラブルシューティング</a></strong>：問題が発生した際に迅速に特定して解決します。</li><li><strong><a href="./../appendix/configuration-reference/">設定リファレンス</a></strong>：完全な設定ファイルスキーマを表示し、すべての設定オプションを理解します。</li><li><strong><a href="./../appendix/claude-code-compatibility/">Claude Code 互換性</a></strong>：既存の Claude Code ワークフローを oh-my-opencode に移行する方法を学びます。</li></ul>`,15)])])}const g=e(r,[["render",t]]);export{u as __pageData,g as default};
